addEventListener("activate",t=>{t.waitUntil((async()=>{try{"storage"in navigator&&"persist"in navigator.storage&&await navigator.storage.persist()}catch{}})())}),addEventListener("sync",t=>{"focus-task-sync"===t.tag&&t.waitUntil(self.clients.matchAll({includeUncontrolled:!0,type:"window"}).then(t=>Promise.all(t.map(t=>t.postMessage({type:"BACKGROUND_SYNC"})))))}),addEventListener("push",t=>{if(!t.data)return;let i={};try{i=t.data.json()}catch{}t.waitUntil(self.registration.showNotification(i.title??"✦ focus",{body:i.body??"",icon:"/icons/icon-192.png",badge:"/icons/icon-96.png",tag:"focus-notification",data:{url:i.url??"/app/today"}}))}),addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.url??"/app/today";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{let n=t.find(t=>t.url.includes(i));return n?n.focus():self.clients.openWindow(i)}))});